  ('real-estate-moex-01987', 'real-estate', 'real-estate-moex-101-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '父親贈與一幢透天建築物給兒子，在正常情況下依土地稅法與契稅條例之規定，下列有關應納稅負之敘 述，何者最正確？', '["父親應繳納土地增值稅與契稅", "父親應繳納土地增值稅，兒子應繳納契稅", "兒子應繳納土地增值稅，父親應繳納契稅", "兒子應繳納土地增值稅與契稅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:10+00:00", "source_pdf_sha1": "326478deef0f", "answer_pdf_sha1": "9e95ee6f73d8", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "601", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法與土地相關稅法概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
